const body = $input.first().json.body;
const { chatInput, sessionId } = body;

if (!chatInput || chatInput.trim().length === 0) {
  throw new Error('Empty message');
}

// Rate limiting awareness - truncate very long messages
const sanitizedInput = chatInput.trim().substring(0, 2000);

// Security: reject messages that look like prompt injection
const suspicious = ['ignore previous', 'system prompt', 'you are now', 'forget your instructions'];
const isSuspicious = suspicious.some(s => sanitizedInput.toLowerCase().includes(s));
if (isSuspicious) {
  return [{ json: { response: 'I can only help with SecureVault-related questions. How can I assist you with encryption or security?', sessionId } }];
}

return [{ json: { chatInput: sanitizedInput, sessionId: sessionId || 'anonymous', timestamp: new Date().toISOString() } }];
